     1→// ==================== CORE TYPES ====================
     2→
     3→export type ViewMode = 'monthly' | 'weekly' | 'daily' | 'agenda';
     4→export type TaskStatus = 'backlog' | 'todo' | 'inprogress' | 'review' | 'done';
     5→export type TaskPriority = 'low' | 'medium' | 'high';
     6→
     7→// ==================== WIDGET DATA TYPES ====================
     8→
     9→export interface CalendarEvent {
    10→  id: string;
    11→  title: string;
    12→  description?: string;
    13→  startTime?: string; // "14:00" (24-hour format)
    14→  endTime?: string;   // "15:30"
    15→  isAllDay?: boolean; // default true if no times specified
    16→
    17→  // Recurrence
    18→  recurrence?: {
    19→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
    20→    interval: number; // e.g., every 2 weeks
    21→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
    22→    dayOfMonth?: number; // 1-31 (for monthly)
    23→    endType: 'never' | 'after' | 'until';
    24→    endCount?: number; // if endType='after'
    25→    endDate?: string; // if endType='until' (YYYY-MM-DD)
    26→  };
    27→  recurrenceId?: string; // For recurring event instances (parent event ID)
    28→  recurrenceException?: boolean; // True if this instance was edited
    29→
    30→  // Multi-day
    31→  endDate?: string; // YYYY-MM-DD (if different from startDate)
    32→
    33→  // Reminders
    34→  reminders?: number[]; // Minutes before event (e.g., [15, 60])
    35→
    36→  // Location
    37→  location?: string;
    38→
    39→  // Multi-day rendering flags (internal, not persisted)
    40→  _isMultiDayPart?: boolean;
    41→  _isMultiDayFirst?: boolean;
    42→  _isMultiDayLast?: boolean;
    43→}
    44→
    45→export interface CalendarState {
    46→  events: Record<string, CalendarEvent[]>; // dateKey -> array of events
    47→  viewMode: ViewMode;
    48→  currentDate: Date;
    49→}
    50→
    51→export type DependencyType =
    52→  | 'finish-to-start'  // Task B starts when A finishes (default)
    53→  | 'start-to-start'   // Task B starts when A starts
    54→  | 'finish-to-finish' // Task B finishes when A finishes
    55→  | 'start-to-finish'; // Task B finishes when A starts (rare)
    56→
    57→export interface TaskDependency {
    58→  taskId: string;           // ID of dependent task
    59→  type: DependencyType;     // Type of dependency
    60→  lag: number;              // Lag time in days (can be negative for lead)
    61→}
    62→
    63→// Phase 4: Column definition for custom Kanban columns
    64→export interface KanbanColumn {
