/**
 * Website Uptime Monitor Widget
 */

import React, { useState, useEffect } from 'react';
import { BaseWidget } from './BaseWidget';
import { useWidgetStore } from '../../stores/useWidgetStore';

interface UptimeWidgetProps {
  widgetId?: string;
}

export const UptimeWidget: React.FC<UptimeWidgetProps> = ({ widgetId = 'uptime' }) => {
  const websites = useWidgetStore((state) => state.widgetSettings[widgetId]?.websites) || [];
  const updateWidgetSettings = useWidgetStore((state) => state.updateWidgetSettings);
  const [input, setInput] = useState('');
  const [statuses, setStatuses] = useState<Record<string, boolean>>({});

  const addWebsite = () => {
    if (input.trim()) {
      updateWidgetSettings(widgetId, { websites: [...websites, input.trim()] });
      setInput('');
    }
  };

  const removeWebsite = (url: string) => {
    updateWidgetSettings(widgetId, { websites: websites.filter((w: string) => w !== url) });
  };

  const checkStatus = async (url: string) => {
    try {
      await fetch(url, { method: 'HEAD', mode: 'no-cors' });
      return true; // If no error, site is up
    } catch {
      return false;
    }
  };

  useEffect(() => {
    const checkAllSites = async () => {
      const newStatuses: Record<string, boolean> = {};
      for (const website of websites) {
        newStatuses[website] = await checkStatus(website);
      }
      setStatuses(newStatuses);
    };

    if (websites.length > 0) {
      checkAllSites();
      const interval = setInterval(checkAllSites, 60000); // Check every minute
      return () => clearInterval(interval);
    }
  }, [websites]);

  return (
    <BaseWidget title="Uptime Monitor" icon="🔔">
      <div className="space-y-3">
        <div className="flex gap-2">
          <input
            type="url"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addWebsite()}
            placeholder="Website URL..."
            className="flex-1 px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue transition-all duration-standard ease-smooth"
          />
          <button onClick={addWebsite} className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth">
            Add
          </button>
        </div>

        <div className="space-y-2">
          {websites.map((website: string, idx: number) => (
            <div key={idx} className="flex items-center justify-between p-2 bg-surface-light-elevated dark:bg-surface-dark rounded-button transition-all duration-standard ease-smooth">
              <div className="flex items-center gap-2 flex-1 truncate">
                <div className={`w-2 h-2 rounded-full ${statuses[website] ? 'bg-status-success' : 'bg-status-error'}`} />
                <a href={website} target="_blank" rel="noopener noreferrer" className="text-sm text-text-light-primary dark:text-text-dark-primary hover:text-accent-blue truncate">
                  {website}
                </a>
              </div>
              <button onClick={() => removeWebsite(website)} className="text-xs text-status-error hover:underline ml-2">
                Remove
              </button>
            </div>
          ))}
        </div>

        {websites.length === 0 && (
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
            Add websites to monitor uptime
          </p>
        )}
      </div>
    </BaseWidget>
  );
};

