/**
 * IndexedDB Service - Unlimited Local Storage
 *
 * Provides a localStorage-like interface with IndexedDB backend
 * Benefits:
 * - 50GB+ storage capacity (vs 5-10MB localStorage)
 * - Handles large data (images, rich text, etc.)
 * - Async operations for better performance
 * - Automatic versioning and migrations
 */

import { logger } from './logger';

const log = logger.module('IndexedDB');

const DB_NAME = 'neuman-brain-db';
const DB_VERSION = 1;
const STORE_NAME = 'brain-data';

interface DBConnection {
  db: IDBDatabase | null;
  isReady: boolean;
}

class IndexedDBService {
  private connection: DBConnection = {
    db: null,
    isReady: false,
  };

  /**
   * Initialize IndexedDB connection
   */
  async init(): Promise<void> {
    if (this.connection.isReady) {
      return;
    }

    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => {
        log.error('Failed to open IndexedDB', { error: request.error });
        reject(request.error);
      };

      request.onsuccess = () => {
        this.connection.db = request.result;
        this.connection.isReady = true;
        log.info('IndexedDB initialized');
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        // Create object store if it doesn't exist
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME);
          log.info('Created IndexedDB object store');
        }
      };
    });
  }

  /**
   * Get item from IndexedDB
   */
  async getItem(key: string): Promise<string | null> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.get(key);

      request.onsuccess = () => {
        resolve(request.result ?? null);
      };

      request.onerror = () => {
        log.error('Failed to get from IndexedDB', { key, error: request.error });
        reject(request.error);
      };
    });
  }

  /**
   * Set item in IndexedDB
   */
  async setItem(key: string, value: string): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(value, key);

      request.onsuccess = () => {
        resolve();
      };

      request.onerror = () => {
        log.error('Failed to set in IndexedDB', { key, error: request.error });
        reject(request.error);
      };
    });
  }

  /**
   * Remove item from IndexedDB
   */
  async removeItem(key: string): Promise<void> {
    await this.init();

    return new Promise((resolve, reject) => {
      if (!this.connection.db) {
        reject(new Error('IndexedDB not initialized'));
        return;
      }

      const transaction = this.connection.db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.delete(key);

      request.onsuccess = () => {
        resolve();
      };

      request.onerror = () => {
        log.error('Failed to remove from IndexedDB', { key, error: request.error });
        reject(request.error);
      };
    });
  }

  /**
   * Get all keys from IndexedDB
   */
  async getAllKeys(): Promise<string[]> {

# Dashboard Widget System - Feature Specification

**Status:** 📋 PROPOSED
**Priority:** P2 (After Sprint 3 - File System Access API)
**Estimated Timeline:** Q2 2026 (Sprint 5-8)
**Owner:** Product Team
**Last Updated:** November 13, 2025

---

## Executive Summary

The Dashboard Widget System will transform the basic Weather + Map dashboard into an **exciting, personalized command center** by adding 5-10 high-impact widgets powered by free public APIs. Users can customize their dashboard with widgets that show relevant real-time data (GitHub stats, crypto prices, news, quotes, etc.).

**Why This Matters:**
- **Current State:** Dashboard is "kinda basic and not exciting" (just weather + map)
- **User Value:** Personalized, glanceable information at-a-glance
- **Differentiation:** No competitor offers this level of customization for free
- **Engagement:** Increased daily usage (users want to see their dashboard)

**Core Principle:** Privacy-first widget system - all API calls client-side, zero tracking, user controls everything.

---

## Problem Statement

### Current Dashboard Limitations

**What We Have:**
```
┌─────────────────────────────────────┐
│  Dashboard                          │
│                                     │
│  ┌──────────┐  ┌──────────┐       │
│  │ Weather  │  │   Map    │       │
│  │   ☀️     │  │   🗺️    │       │
│  └──────────┘  └──────────┘       │
│                                     │
│  (pretty basic, not exciting)      │
└─────────────────────────────────────┘
```

**User Feedback:**
- "Just weather and a map? That's it?"
