  config: WidgetConfig;          // Widget-specific configuration
  position: { x: number; y: number; w: number; h: number }; // Grid layout
}

export interface WidgetConfig {
  apiKey?: string;               // Optional API key (stored in IndexedDB)
  refreshInterval?: number;      // Minutes between refreshes
